appsmith.onReady(() => {
  renderExposureSignals();
});
appsmith.onModelChange(() => {
  renderExposureSignals();
});
function renderExposureSignals() {
  const data = appsmith.model;
  const piiData = data.pii_data || {
    total_pii: 0,
    pii_types: []
  };
  const heuristics = data.inference_heuristics || {};

  // Helper to apply status styling
  function applyStatus(cardId, badgeId, statusText, level) {
    const card = document.getElementById(cardId);
    const badge = document.getElementById(badgeId);
    badge.textContent = statusText;
    card.className = "exposure-card"; // reset

    if (level === "CRITICAL") {
      card.classList.add("border-critical");
      badge.className = "badge badge-critical";
    } else if (level === "WARNING") {
      card.classList.add("border-warning");
      badge.className = "badge badge-warning";
    } else if (level === "SAFE") {
      card.classList.add("border-safe");
      badge.className = "badge badge-safe";
    }
  }

  // Helper to render indicator lists
  function renderList(listId, items) {
    const listEl = document.getElementById(listId);
    listEl.innerHTML = "";
    items.forEach(item => {
      const li = document.createElement('li');
      li.textContent = item;
      listEl.appendChild(li);
    });
  }

  // 1. Model Inversion Logic (Using Real Data)
  const rawIdentifiers = ["FirstName", "LastName"];
  const foundIdentifiers = piiData.pii_types.filter(t => rawIdentifiers.includes(t));
  if (foundIdentifiers.length > 0) {
    applyStatus("card-inversion", "badge-inversion", "ELEVATED RISK", "CRITICAL");
    renderList("list-inversion", [`Presence of raw identifiers detected: ${foundIdentifiers.join(", ")}.`, "High-cardinality strings mapped directly to features.", "Strong drivers for inversion attacks."]);
  } else {
    applyStatus("card-inversion", "badge-inversion", "NOMINAL", "SAFE");
    renderList("list-inversion", ["No direct mapping features or high-cardinality identifiers detected in input schema."]);
  }

  // 2. Membership Inference Logic (Simulated Heuristics)
  const memInf = heuristics.membership_inference || {};
  applyStatus("card-membership", "badge-membership", memInf.status.toUpperCase(), memInf.status === "Elevated" ? "WARNING" : "SAFE");
  renderList("list-membership", memInf.indicators || ["Awaiting data."]);

  // 3. Output Leakage Logic (Simulated Heuristics)
  const outLeak = heuristics.output_leakage || {};
  applyStatus("card-leakage", "badge-leakage", outLeak.status.toUpperCase(), outLeak.status === "Elevated" ? "CRITICAL" : "SAFE");
  renderList("list-leakage", outLeak.indicators || ["Awaiting data."]);

  // 4. Logging Persistence Logic (Simulated Heuristics)
  const logPersist = heuristics.logging_persistence || {};
  applyStatus("card-logging", "badge-logging", logPersist.status.toUpperCase(), logPersist.status === "Exposed" ? "WARNING" : "SAFE");
  renderList("list-logging", logPersist.indicators || ["Awaiting data."]);
}

